const payload = $('Threshold Exceeded Webhook').item.json.body;
const ai = $('Get Instant AI Tip').item.json;
const overBy = ((payload.daily - payload.average) / payload.average * 100).toFixed(0);

const message = [
  `⚠️ High Carbon Alert — ${overBy}% above your average!`,
  `Today: ${payload.daily?.toFixed(2)} kg CO₂e (avg: ${payload.average?.toFixed(2)} kg)`,
  `Main source: ${payload.category}`,
  ``,
  `💡 AI Tip: ${ai.insight ?? 'Try to offset with a greener commute tomorrow.'}`,
  ai.suggestions?.[0] ? `→ ${ai.suggestions[0].action} (saves ~${ai.suggestions[0].estimatedSavingKg} kg)` : '',
].filter(Boolean).join('\n');

return [{ json: { message, daily: payload.daily, average: payload.average, category: payload.category } }];
